import redis
import json
import sys

class RedisLuaClient:
    def __init__(self, host='localhost', port=6379, db=0, password=None):
        self.client = redis.Redis(
            host=host,
            port=port,
            db=db,
            password=password,
            decode_responses=True
        )
    
    def execute_lua_script(self, script, keys=None, args=None):
        if keys is None:
            keys = []
        if args is None:
            args = []
        
        result = self.client.eval(script, len(keys), *keys, *args)
        return result
    
    def execute_lua_from_input(self):
        print("Enter Lua script (end with 'END' on a new line):")
        script_lines = []
        while True:
            line = input()
            if line.strip() == 'END':
                break
            script_lines.append(line)
        
        script = '\n'.join(script_lines)
        
        keys_input = input("Enter keys (comma-separated, or press Enter for none): ").strip()
        keys = [k.strip() for k in keys_input.split(',')] if keys_input else []
        
        args_input = input("Enter arguments (comma-separated, or press Enter for none): ").strip()
        args = [a.strip() for a in args_input.split(',')] if args_input else []
        
        result = self.execute_lua_script(script, keys, args)
        return result
    
    def batch_set_with_expiry(self, data_dict, expiry_seconds):
        script = """
        local expiry = ARGV[1]
        local count = 0
        for i = 1, #KEYS do
            redis.call('SET', KEYS[i], ARGV[i+1])
            redis.call('EXPIRE', KEYS[i], expiry)
            count = count + 1
        end
        return count
        """
        keys = list(data_dict.keys())
        args = [str(expiry_seconds)] + list(data_dict.values())
        return self.execute_lua_script(script, keys, args)
    
    def atomic_increment_with_limit(self, key, increment, max_value):
        script = """
        local current = redis.call('GET', KEYS[1])
        if not current then
            current = 0
        else
            current = tonumber(current)
        end
        local increment = tonumber(ARGV[1])
        local max_value = tonumber(ARGV[2])
        local new_value = current + increment
        if new_value <= max_value then
            redis.call('SET', KEYS[1], new_value)
            return new_value
        else
            return -1
        end
        """
        return self.execute_lua_script(script, [key], [str(increment), str(max_value)])
    
    def conditional_update(self, key, old_value, new_value):
        script = """
        local current = redis.call('GET', KEYS[1])
        if current == ARGV[1] then
            redis.call('SET', KEYS[1], ARGV[2])
            return 1
        else
            return 0
        end
        """
        return self.execute_lua_script(script, [key], [old_value, new_value])
    
    def get_and_delete(self, key):
        script = """
        local value = redis.call('GET', KEYS[1])
        if value then
            redis.call('DEL', KEYS[1])
            return value
        else
            return nil
        end
        """
        return self.execute_lua_script(script, [key], [])
    
    def multi_key_operation(self, operation, keys, values=None):
        if operation == 'mget':
            script = """
            local results = {}
            for i = 1, #KEYS do
                results[i] = redis.call('GET', KEYS[i])
            end
            return results
            """
            return self.execute_lua_script(script, keys, [])
        elif operation == 'mset':
            script = """
            for i = 1, #KEYS do
                redis.call('SET', KEYS[i], ARGV[i])
            end
            return 'OK'
            """
            return self.execute_lua_script(script, keys, values or [])
        elif operation == 'mdel':
            script = """
            local count = 0
            for i = 1, #KEYS do
                count = count + redis.call('DEL', KEYS[i])
            end
            return count
            """
            return self.execute_lua_script(script, keys, [])
    
    def rate_limiter(self, key, max_requests, window_seconds):
        script = """
        local key = KEYS[1]
        local max_requests = tonumber(ARGV[1])
        local window = tonumber(ARGV[2])
        local current = redis.call('GET', key)
        
        if not current then
            redis.call('SET', key, 1)
            redis.call('EXPIRE', key, window)
            return 1
        else
            current = tonumber(current)
            if current < max_requests then
                redis.call('INCR', key)
                return current + 1
            else
                return -1
            end
        end
        """
        return self.execute_lua_script(script, [key], [str(max_requests), str(window_seconds)])
    
    def custom_cache_operation(self, script_code, keys_list, args_list):
        return self.execute_lua_script(script_code, keys_list, args_list)


